// The fold function f takes &mut Acc and &T.
// With HRTB, the exact lifetime of Acc and T are quantified at each call.
fn fold_with_ref<T, Acc, F>(slice: &[T], init: &mut Acc, f: F)
where
    F: for<'a, 'b> Fn(&'a mut Acc, &'b T),
{
    for item in slice {
        f(init, item);
    }
}

// Multi-lifetime HRTB: for<'a, 'b> means both lifetimes are universally quantified
fn main() {
    let nums = vec![1i32, 2, 3, 4, 5];
    let mut sum = 0i32;
    fold_with_ref(&nums, &mut sum, |acc, x| *acc += x);
    println!("sum: {}", sum);

    let words = vec!["hello", "world"];
    let mut combined = String::new();
    fold_with_ref(&words, &mut combined, |acc, w| {
        if !acc.is_empty() { acc.push(' '); }
        acc.push_str(w);
    });
    println!("{}", combined);
}

