// HRTBs require the closure to work for ALL lifetimes, not just some.
// Closures that STORE references are restricted to specific lifetimes.

fn apply_hrtb<F>(strings: &[&str], f: F) -> Vec<usize>
where
    F: for<'a> Fn(&'a str) -> usize, // quantified: any &str lifetime
{
    strings.iter().map(|s| f(s)).collect()
}

// This closure is fine: it doesn't store anything, works for any 'a:
fn main() {
    let words = vec!["hello", "world"];
    let lengths = apply_hrtb(&words, |s| s.len()); // OK: no storage
    println!("{:?}", lengths);

    // Named function also fine (equivalent HRTB):
    let lengths2 = apply_hrtb(&words, str::len);
    println!("{:?}", lengths2);

    // A closure that *captures* a reference cannot always satisfy HRTB:
    let prefix = String::from("pre");
    // This closure's return value borrows from `prefix`, which has a fixed lifetime:
    let add_prefix = |s: &str| -> usize { s.len() + prefix.len() }; // OK: returns usize
    let lengths3 = apply_hrtb(&words, add_prefix);
    println!("{:?}", lengths3);
