// This function works for any T and any property.
fn assert_property<T, F>(val: &T, prop: F, msg: &str)
where
    F: for<'a> Fn(&'a T) -> bool, // explicit HRTB
{
    assert!(prop(val), "{}: property failed for {:?}", msg,
        std::any::type_name::<T>());
}

