// Chain with owned values: no HRTB needed
fn chain<A, B, C, F: Fn(A) -> B, G: Fn(B) -> C>(val: A, f: F, g: G) -> C {
    g(f(val))
}

// Chain with borrowed values: HRTB needed to connect lifetimes
fn chain_refs<F, G>(s: &str, f: F, g: G) -> usize
where
    F: for<'a> Fn(&'a str) -> &'a str,
    G: for<'a> Fn(&'a str) -> usize,
{
    g(f(s))
}

fn main() {
    // Owned chain:
    let result = chain(String::from("hello"), |s| s.len(), |n| n * 2);
    println!("{}", result); // 10

    // Reference chain:
    let s = String::from("  hello world  ");
    let word_count = chain_refs(&s, str::trim, |s| s.split_whitespace().count());
    println!("words: {}", word_count); // 2

    // Works with different-lifetime inputs:
    let owned = String::from("  test string  ");
    let count = chain_refs(&owned, str::trim, str::len);
    println!("trimmed len: {}", count);
}

